using Dapper; using ValoraPesquisa.Application.Contracts; using ValoraPesquisa.Domain.Entities; using ValoraPesquisa.Domain.Enums; using ValoraPesquisa.Infrastructure.Database;
namespace ValoraPesquisa.Infrastructure.Repositories;
public sealed class AuditService(PostgresConnectionFactory db):IAuditService{ public async Task RecordAsync(Guid? orgId,Guid? userId,string action,string entity,Guid? entityId,string correlationId,object? metadata=null){ using var c=db.Create(); await c.ExecuteAsync("insert into valorapesquisa.audit_logs(organization_id,user_id,action,entity,entity_id,correlation_id,metadata) values(@orgId,@userId,@action,@entity,@entityId,@correlationId,cast(@metadata as jsonb))", new{orgId,userId,action,entity,entityId,correlationId,metadata=System.Text.Json.JsonSerializer.Serialize(metadata??new{})}); }}
public static class Scope{ public static void DemandOrg(CurrentUser u,Guid org){ if(!u.IsAdminValora && u.OrganizationId!=org) throw new UnauthorizedAccessException("Acesso negado para esta organização."); }}
public sealed class UserRepository(PostgresConnectionFactory db):IUserRepository{ public async Task<User?> FindByEmailAsync(string email){using var c=db.Create(); return await c.QuerySingleOrDefaultAsync<User>("select * from valorapesquisa.users where lower(email)=lower(@email) and is_deleted=false",new{email});} public async Task<User?> FindByIdAsync(Guid id){using var c=db.Create(); return await c.QuerySingleOrDefaultAsync<User>("select * from valorapesquisa.users where id=@id and is_deleted=false",new{id});} public async Task UpdateLastLoginAsync(Guid id){using var c=db.Create(); await c.ExecuteAsync("update valorapesquisa.users set last_login_at=now() where id=@id",new{id});} public async Task<IReadOnlyList<User>> ListAsync(CurrentUser u){using var c=db.Create(); return (await c.QueryAsync<User>(u.IsAdminValora?"select * from valorapesquisa.users where is_deleted=false":"select * from valorapesquisa.users where organization_id=@OrganizationId and is_deleted=false",u)).ToList();} public async Task<User> CreateAsync(User user){using var c=db.Create(); await c.ExecuteAsync("insert into valorapesquisa.users(id,organization_id,name,email,password_hash,role,status,phone,is_deleted) values(@Id,@OrganizationId,@Name,@Email,@PasswordHash,@Role,@Status,@Phone,@IsDeleted)",user); return user;} }
public sealed class OrganizationRepository(PostgresConnectionFactory db):IOrganizationRepository{ public async Task<IReadOnlyList<Organization>> ListAsync(){using var c=db.Create(); return (await c.QueryAsync<Organization>("select * from valorapesquisa.organizations where is_deleted=false order by name")).ToList();} public async Task<Organization> CreateAsync(Organization o){using var c=db.Create(); await c.ExecuteAsync("insert into valorapesquisa.organizations(id,name,public_name,slug,document,email,phone,status,plan_code,created_by,updated_by,is_deleted) values(@Id,@Name,@PublicName,@Slug,@Document,@Email,@Phone,@Status,@PlanCode,@CreatedBy,@UpdatedBy,@IsDeleted)",o); return o;} public async Task<Organization?> FindBySlugAsync(string slug){using var c=db.Create(); return await c.QuerySingleOrDefaultAsync<Organization>("select * from valorapesquisa.organizations where slug=@slug and is_deleted=false",new{slug});} }
// Additional repositories follow the same Dapper pattern and keep token_hash/password_hash out of DTOs returned by controllers.
